import{_ as e,o,c as t,ag as n}from"./chunks/framework.D2Ob5GRY.js";const m=JSON.parse('{"title":"令牌机制说明（技术用户）","description":"","frontmatter":{},"headers":[],"relativePath":"account/token-mechanism.md","filePath":"account/token-mechanism.md"}'),r={name:"account/token-mechanism.md"};function i(l,a,s,c,h,d){return o(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="令牌机制说明-技术用户" tabindex="-1">令牌机制说明（技术用户） <a class="header-anchor" href="#令牌机制说明-技术用户" aria-label="Permalink to &quot;令牌机制说明（技术用户）&quot;">​</a></h1><blockquote><p>令牌是什么、自动续签原理、离线行为与缓存文件位置。</p></blockquote><h2 id="令牌是什么-有效期多长" tabindex="-1">令牌是什么，有效期多长 <a class="header-anchor" href="#令牌是什么-有效期多长" aria-label="Permalink to &quot;令牌是什么，有效期多长&quot;">​</a></h2><p>主产品通过「container-token」或「授权码」从门户获取访问令牌，用于后续 API 调用。账号路径下令牌有效期通常为数天（如 7 天），授权码路径下由门户签发 signed_token，具体以门户配置为准。</p><h2 id="令牌自动续签的工作原理" tabindex="-1">令牌自动续签的工作原理 <a class="header-anchor" href="#令牌自动续签的工作原理" aria-label="Permalink to &quot;令牌自动续签的工作原理&quot;">​</a></h2><ul><li><strong>账号路径</strong>：主产品后台有续签任务，在令牌过期前向门户请求新 token 并更新内存与缓存。</li><li><strong>授权码路径</strong>：定期心跳请求门户，若返回新 signed_token 则更新本地缓存。</li></ul><h2 id="离线时令牌的行为-最长支撑-24-小时" tabindex="-1">离线时令牌的行为（最长支撑 24 小时） <a class="header-anchor" href="#离线时令牌的行为-最长支撑-24-小时" aria-label="Permalink to &quot;离线时令牌的行为（最长支撑 24 小时）&quot;">​</a></h2><p>续签依赖网络；离线后到期则无法获取新 token，主产品可能拒绝请求或提示重新联网校验。授权码路径下若已缓存未过期的 signed_token，可在离线期内继续使用直至过期。</p><h2 id="令牌缓存文件位置及手动清除方法" tabindex="-1">令牌缓存文件位置及手动清除方法 <a class="header-anchor" href="#令牌缓存文件位置及手动清除方法" aria-label="Permalink to &quot;令牌缓存文件位置及手动清除方法&quot;">​</a></h2><ul><li><strong>账号路径</strong>：通常为 <code>CONFIG_DIR/token.json</code>（具体以主产品文档为准）。</li><li><strong>授权码路径</strong>：<code>CONFIG_DIR/license_token.json</code>。</li><li>手动清除：删除对应文件后重启主产品，将重新向门户请求校验（需网络）。</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/troubleshooting/common-errors.html">常见错误与解决方法</a></li><li><a href="/docs/account/machine-management.html">机器管理</a></li></ul>',12)])])}const _=e(r,[["render",i]]);export{m as __pageData,_ as default};
